import React, { useState } from "react";
import {
  RadarChart, Radar, PolarGrid, PolarAngleAxis,
  ResponsiveContainer, BarChart, Bar, XAxis, YAxis,
  Tooltip, Cell
} from "recharts";
import "./Results.css";

// Professional, business-friendly palette
const ACCENT_COLORS = [
  "#1d4ed8", // blue
  "#0f766e", // teal
  "#b45309", // amber
  "#7c3aed", // violet
  "#be123c", // rose
  "#0369a1", // sky
  "#15803d", // green
  "#c2410c", // orange
];

const SEGMENT_ICONS = {
  "Champions":            "🏆",
  "Loyal Customers":      "💎",
  "Potential Loyalists":  "🌱",
  "At Risk":              "⚠️",
  "Cannot Lose Them":     "🔥",
  "Hibernating":          "❄️",
  "Lost Customers":       "💤",
  "New Customers":        "✨",
};

export default function Results({ data, onReset }) {
  const [activeCluster, setActiveCluster] = useState(0);
  const {
    total_customers, total_transactions, best_k,
    silhouette_scores, profiles, columns_detected, meta
  } = data;

  const active = profiles[activeCluster];
  const color  = ACCENT_COLORS[activeCluster % ACCENT_COLORS.length];
  const hasProxyRecency = meta && !meta.has_true_recency;

  const silData = Object.entries(silhouette_scores).map(([k, v]) => ({
    k: `k=${k}`, score: v, best: parseInt(k) === best_k,
  }));

  const maxR = Math.max(...profiles.map((p) => p.mean_recency));
  const maxF = Math.max(...profiles.map((p) => p.mean_frequency));
  const maxM = Math.max(...profiles.map((p) => p.mean_monetary));

  const radarData = [
    { metric: "Recency⁻¹", value: Math.round((1 - active.mean_recency / maxR) * 100) },
    { metric: "Frequency",  value: Math.round((active.mean_frequency  / maxF) * 100) },
    { metric: "Monetary",   value: Math.round((active.mean_monetary   / maxM) * 100) },
  ];

  return (
    <div className="results">
      {/* ── Summary bar ── */}
      <div className="summary-bar">
        <StatBadge label="Total Customers"   value={total_customers.toLocaleString()} />
        <StatBadge label="Total Transactions" value={total_transactions.toLocaleString()} />
        <StatBadge label="Segments Found"    value={best_k} accent />
        <StatBadge label="Best Silhouette"   value={silhouette_scores[best_k].toFixed(4)} />
        <button className="reset-btn" onClick={onReset}>↩ Upload new file</button>
      </div>

      {/* ── Detected columns ── */}
      <div className="detected-cols">
        <span className="detected-label">Columns used:</span>
        {Object.entries(columns_detected).map(([k, v]) => (
          <span key={k} className="detected-chip">
            <span className="chip-key">{k.replace(/_/g, " ")}</span>
            <span className="chip-val">{v}</span>
          </span>
        ))}
      </div>

      {/* ── Proxy recency notice ── */}
      {hasProxyRecency && (
        <div className="proxy-notice">
          <span className="proxy-icon">ℹ</span>
          <span>
            No date column detected. <strong>Recency</strong> is estimated from row order —
            customers appearing later in the file are treated as more recent.
            {meta?.recency_source && <> Source: <code>{meta.recency_source}</code></>}
          </span>
        </div>
      )}

      <div className="results-body">
        {/* ── Left: segment list ── */}
        <div className="cluster-list">
          <p className="section-label">Customer Segments</p>
          {profiles.map((p, i) => (
            <div
              key={i}
              className={`cluster-card ${i === activeCluster ? "active" : ""}`}
              style={{ "--card-color": ACCENT_COLORS[i % ACCENT_COLORS.length] }}
              onClick={() => setActiveCluster(i)}
            >
              <div className="card-header">
                <span className="card-icon">{SEGMENT_ICONS[p.segment] || "◉"}</span>
                <div>
                  <p className="card-segment">{p.segment}</p>
                  <p className="card-cluster">Cluster {p.cluster}</p>
                </div>
                <span className="card-pct">{p.pct_customers}%</span>
              </div>
              <div className="card-bar-wrap">
                <div className="card-bar" style={{ width: `${p.pct_customers}%` }} />
              </div>
              <div className="card-stats">
                <MiniStat label="R" value={`${p.mean_recency}${hasProxyRecency ? "" : "d"}`} />
                <MiniStat label="F" value={p.mean_frequency} />
                <MiniStat label="M" value={`$${p.mean_monetary >= 1000
                  ? (p.mean_monetary / 1000).toFixed(1) + "k"
                  : p.mean_monetary.toFixed(0)}`}
                />
              </div>
            </div>
          ))}
        </div>

        {/* ── Right: detail panel ── */}
        <div className="detail-panel">
          <div className="detail-header" style={{ "--panel-color": color }}>
            <span className="detail-icon">{SEGMENT_ICONS[active.segment] || "◉"}</span>
            <div>
              <h2 className="detail-segment">{active.segment}</h2>
              <p className="detail-sub">
                {active.size.toLocaleString()} customers &nbsp;·&nbsp; {active.pct_customers}% of total base
              </p>
            </div>
          </div>

          {/* ── Metrics ── */}
          <div className="metrics-grid">
            <MetricCard
              label={hasProxyRecency ? "Recency (proxy)" : "Avg. Recency"}
              mean={hasProxyRecency ? active.mean_recency : `${active.mean_recency} days`}
              median={hasProxyRecency ? active.median_recency : `${active.median_recency} days`}
              note={hasProxyRecency ? "Row-order proxy — lower = more recent" : "Days since last purchase"}
              color={color}
            />
            <MetricCard
              label="Avg. Frequency"
              mean={active.mean_frequency}
              median={active.median_frequency}
              note={meta?.frequency_source || "Distinct transactions"}
              color={color}
            />
            <MetricCard
              label="Avg. Monetary"
              mean={`$${active.mean_monetary.toLocaleString(undefined, { maximumFractionDigits: 2 })}`}
              median={`$${active.median_monetary.toLocaleString(undefined, { maximumFractionDigits: 2 })}`}
              note={meta?.monetary_source || "Total spend per customer"}
              color={color}
            />
          </div>

          {/* ── Charts ── */}
          <div className="charts-row">
            <div className="chart-box">
              <p className="chart-title">RFM Profile</p>
              <ResponsiveContainer width="100%" height={200}>
                <RadarChart data={radarData}>
                  <PolarGrid stroke="#e2e0db" />
                  <PolarAngleAxis
                    dataKey="metric"
                    tick={{ fill: "#8a8680", fontSize: 11, fontFamily: "IBM Plex Mono" }}
                  />
                  <Radar
                    dataKey="value"
                    stroke={color}
                    fill={color}
                    fillOpacity={0.15}
                    strokeWidth={2}
                  />
                </RadarChart>
              </ResponsiveContainer>
            </div>

            <div className="chart-box">
              <p className="chart-title">K Selection — Silhouette Scores</p>
              <ResponsiveContainer width="100%" height={200}>
                <BarChart data={silData} margin={{ left: -10 }}>
                  <XAxis
                    dataKey="k"
                    tick={{ fill: "#8a8680", fontSize: 11, fontFamily: "IBM Plex Mono" }}
                    axisLine={false} tickLine={false}
                  />
                  <YAxis
                    tick={{ fill: "#8a8680", fontSize: 10, fontFamily: "IBM Plex Mono" }}
                    axisLine={false} tickLine={false}
                    domain={[0, 1]}
                  />
                  <Tooltip
                    contentStyle={{
                      background: "#fff",
                      border: "1px solid #e2e0db",
                      borderRadius: 8,
                      fontFamily: "IBM Plex Mono",
                      fontSize: 12,
                      color: "#1a1a1a",
                      boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
                    }}
                    cursor={{ fill: "rgba(0,0,0,0.03)" }}
                  />
                  <Bar dataKey="score" radius={[4, 4, 0, 0]}>
                    {silData.map((entry, i) => (
                      <Cell key={i} fill={entry.best ? "#1d4ed8" : "#e2e0db"} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
              <p className="chart-note">Blue bar = selected k ({best_k})</p>
            </div>
          </div>

          {/* ── Comparison table ── */}
          <div className="comparison-table-wrap">
            <p className="section-label" style={{ marginBottom: 12 }}>All Segments Comparison</p>
            <div className="comparison-table">
              <div className="ct-head">
                <span>Segment</span>
                <span>Customers</span>
                <span>Share</span>
                <span>{hasProxyRecency ? "Recency*" : "Avg Recency"}</span>
                <span>Avg Frequency</span>
                <span>Avg Monetary</span>
              </div>
              {profiles.map((p, i) => (
                <div
                  key={i}
                  className={`ct-row ${i === activeCluster ? "ct-active" : ""}`}
                  style={{ "--row-color": ACCENT_COLORS[i % ACCENT_COLORS.length] }}
                  onClick={() => setActiveCluster(i)}
                >
                  <span className="ct-seg">
                    <span className="ct-dot" />
                    {p.segment}
                  </span>
                  <span>{p.size.toLocaleString()}</span>
                  <span>{p.pct_customers}%</span>
                  <span>{p.mean_recency}{hasProxyRecency ? "" : "d"}</span>
                  <span>{p.mean_frequency}</span>
                  <span>${p.mean_monetary >= 1000
                    ? (p.mean_monetary / 1000).toFixed(1) + "k"
                    : p.mean_monetary.toFixed(2)}</span>
                </div>
              ))}
            </div>
            {hasProxyRecency && (
              <p className="table-footnote">* Recency = row-order proxy (no date column in dataset)</p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

function StatBadge({ label, value, accent }) {
  return (
    <div className={`stat-badge ${accent ? "stat-accent" : ""}`}>
      <span className="stat-value">{value}</span>
      <span className="stat-label">{label}</span>
    </div>
  );
}

function MiniStat({ label, value }) {
  return (
    <div className="mini-stat">
      <span className="mini-label">{label}</span>
      <span className="mini-value">{value}</span>
    </div>
  );
}

function MetricCard({ label, mean, median, note, color }) {
  return (
    <div className="metric-card" style={{ "--mc-color": color }}>
      <p className="mc-label">{label}</p>
      <p className="mc-mean">{mean}</p>
      <p className="mc-median">Median: {median}</p>
      <p className="mc-note">{note}</p>
    </div>
  );
}
